// src/api/products.ts
export interface Product {
  id: string;
  name: string;
  priceCents: number;
}

const CATALOG: Product[] = [
  { id: "p1", name: "Widget", priceCents: 500 },
  { id: "p2", name: "Gadget", priceCents: 1200 },
  { id: "p3", name: "Gizmo", priceCents: 800 },
];

// Returns the ENTIRE catalog — no paging yet (the feature to plan).
export function listProducts(): Product[] {
  return CATALOG.slice();
}

// src/payments/charge.ts
export interface ChargeResult {
  id: string;
  amountCents: number;
}

let seq = 0;

// EXISTING production function — its signature is frozen (callers depend on it).
export async function charge(
  customerId: string,
  amountCents: number,
  currency: string,
): Promise<ChargeResult> {
  seq += 1;
  return { id: `ch_${customerId}_${seq}`, amountCents };
}
